TEST(TestHiddenSingle, HiddenSingleFound1) {
    auto res = std::make_pair(true, "Hidden Single: r5c9=1");

    Inst inst = {0x01,0x48,0x00};
    Exec exec = {true, std::vector<u_int16_t>{0x4800}};
    Grid grid("");
    findHiddenSingle(grid);
    EXPECT_EQ(grid.execution, exec);
    EXPECT_EQ(grid.instructions, inst);

}

